from .telemetry import telemetry_client

SDK_NAME = "python-sdk"
try:
    __version__ = version("gridspace-guava")
except PackageNotFoundError:
    __version__ = "0+unknown"


__all__ = ["CallController", "Client", "Field", "Say", "Todo"]



logger = logging.getLogger("guava")



U = TypeVar("U", bound=CallController)

first_client = FirstEntry()

@telemetry_client.track_class()
class Client:
    def __init__(self, api_key: Optional[str] = None, base_url: Optional[str] = None):
        if base_url:
            self._base_url = base_url
        else:
            self._base_url = get_base_url()

        if api_key:
            self._api_key = api_key
        elif 'GUAVA_API_KEY' in os.environ:
            self._api_key = os.environ['GUAVA_API_KEY']
        else:
            raise Exception("Guava API key must be provided either as argument to client constructor, or in environment variable GUAVA_API_KEY.")
        
        if first_client.claim():
            # Set SDK headers for telemetry uploads.
            telemetry_client.set_sdk_headers(self._get_headers())

            logger.debug("Checking deprecation for SDK %s, %s.", SDK_NAME, __version__)
            try:
                r = httpx.post(self.get_http_url("v1/check-sdk-deprecation"), params={
                    "sdk_name": SDK_NAME,
                    "sdk_version": __version__
                })
                r.raise_for_status()
                deprecation_info = r.json()
                
                match deprecation_info["deprecation_status"]:
                    case "supported":
                        logger.info("SDK version still supported.")
                    case "deprecated":
                        warnings.warn("This SDK version is deprecated. Please update to a newer version of the SDK.", UserWarning)
                    case _:
                        logger.warning("SDK deprecation status unknown.")
            except Exception:
                logger.exception("Encountered issue while checking for deprecation.")

    def _get_http_base(self) -> str:
        return self._base_url
    
    def _get_websocket_base(self) -> str:
        if self._base_url.startswith("http://"):
            return "ws://" + self._base_url[len("http://"):]
        elif self._base_url.startswith("https://"):
            return "wss://" + self._base_url[len("https://"):]
        else:
            raise Exception("Invalid base URL: " + self._base_url)
        
    def get_http_url(self, path: str) -> str:
        return urljoin(self._get_http_base(), path)
    
    def get_websocket_url(self, path: str) -> str:
        return urljoin(self._get_websocket_base(), path)

    def _get_headers(self) -> dict[str, str]:
        return {
            "Authorization": f"Bearer {self._api_key}",
            "x-guava-platform": platform.system(),
            "x-guava-runtime": platform.python_implementation(),
            "x-guava-runtime-version": platform.python_version(),
            "x-guava-sdk": SDK_NAME,
            "x-guava-sdk-version": __version__,
        }
    
    def create_webrtc_agent(self) -> str:
        r = httpx.post(self.get_http_url("v1/webrtc-agents"), headers=self._get_headers())
        r.raise_for_status()
        return r.json()['webrtc_code']

    def create_sip_agent(self) -> str:
        r = httpx.post(self.get_http_url("v1/sip-agents"), headers=self._get_headers())
        r.raise_for_status()
        return r.json()['sip_code']
    
    def set_inbound_handler(self, agent_number, public_url, inbound_token):
        r = httpx.put(
            self.get_http_url(f"v1/inbound-handler/{agent_number}"),
            headers=self._get_headers(),
            json={
                'handler_url': public_url,
                'handler_token': inbound_token
            }
        )
        r.raise_for_status()

    def create_outbound(
        self,
        *,
        from_number: Optional[str] = None,
        to_number: str,
        call_controller: Optional[CallController] = None,
    ):
        try:
            last_seen_event_seq = 0
            with connect(
                self.get_websocket_url("v1/create-outbound"),
                additional_headers=self._get_headers(),
            ) as websocket:
                # Send a start outbound call command and wait for a session started event in response.
                websocket.send(
                    StartOutboundCallCommand(
                        from_number=from_number,
                        to_number=to_number,
                    ).model_dump_json()
                )
                session_started: Union[OutboundSessionStartedEvent, ErrorEvent]  = TypeAdapter(Union[OutboundSessionStartedEvent, ErrorEvent]).validate_json(websocket.recv())
                if isinstance(session_started, ErrorEvent):
                    raise Exception("Outbound call failed: " + session_started.content)

                logger.info("Started session with ID: %s", session_started.session_id)

                if call_controller:
                    threading.Thread(
                        target=call_controller._drain_command_queue_thread,
                        daemon=True,
                        args=(websocket,),
                    ).start()

                while True:
                    serialized_event = websocket.recv()
                    event = decode_event(serialized_event)

                    if event is None:
                        continue

                    if event.sequence:
                        if event.sequence <= last_seen_event_seq:
                            logger.error("Got an event with an unexpected sequence number: %d. Expected events > %d. Ignoring event.", event.sequence, last_seen_event_seq)
                            continue
                        else:
                            last_seen_event_seq = event.sequence

                    if call_controller:
                        if isinstance(event, OutboundCallFailed) or isinstance(event, BotSessionEnded):
                            # These two events get run on the main thread
                            call_controller.on_event(event)
                        else:
                            # Run event on it's own thread, to allow for awaiting. This could be a threadpool, but you could
                            # still exhaust the pool with a bunch of await tasks, and thus deadlock a controller.
                            threading.Thread(target=call_controller.on_event, daemon=True, args=(event,)).start()

                    
                    if isinstance(event, OutboundCallFailed) or isinstance(event, BotSessionEnded):
                        break


        except websockets.exceptions.InvalidStatus as e:
            raise Exception("Server rejected connection: " + e.response.body.decode())

        if call_controller:
            call_controller.shutdown()

    def listen_inbound(
        self, 
        *, 
        agent_number: Optional[str] = None, 
        webrtc_code: Optional[str] = None,
        sip_code: Optional[str] = None,
        controller_class: Type[U], 
        controller_args: dict = {}
    ):
        if agent_number is None and webrtc_code is None and sip_code is None:
            raise ValueError("One of agent_number, webrtc_code, or sip_code must be provided.")
        
        call_controllers: dict[str, U] = {}

        with connect(
            self.get_websocket_url("v1/listen-inbound"),
            additional_headers=self._get_headers(),
        ) as websocket:
            websocket.send(
                ListenInboundCommand(agent_number=agent_number, webrtc_code=webrtc_code, sip_code=sip_code).model_dump_json(),
            )

            logger.info("Listening for calls to %s", agent_number or webrtc_code or sip_code)

            if webrtc_code:
                print(f"WebRTC DebugURL: {self.get_http_url('debug-webrtc')}?webrtc_code={webrtc_code}")
            
            if sip_code:
                logger.info(f"SIP agent active: {sip_code}")

            def drain_controller_commands(call_id, call_controller):
                while True:
                    command = call_controller._command_queue.get(block=True)
                    logger.debug(
                        "Sending command: %r for call ID: %s", command, call_id
                    )
                    websocket.send(
                        InboundTunnelCommand(
                            call_id=call_id, command=command
                        ).model_dump_json()
                    )

            while True:
                tunnel_event = InboundTunnelEvent.model_validate_json(websocket.recv())
                if tunnel_event.call_id not in call_controllers:
                    logger.info(
                        "Recieved tunnel event for new call ID: %s. Creating call controller.",
                        tunnel_event.call_id,
                    )
                    # TODO: Eventually clean this up
                    call_controllers[tunnel_event.call_id] = controller_class(**controller_args)
                    
                    # Start a thread to drain commands from this controller and post them to the websocket.
                    threading.Thread(
                        target=drain_controller_commands,
                        daemon=True,
                        args=(
                            tunnel_event.call_id,
                            call_controllers[tunnel_event.call_id],
                        ),
                    ).start()

                # Process event on it's own thread, to allow for awaiting.
                threading.Thread(target=call_controllers[tunnel_event.call_id].on_event, daemon=True, args=(tunnel_event.event,)).start()

    @preview("listen_inbound_v2")
    def listen_inbound_v2(self, *, agent_number: str, controller_class: Type[U], controller_args: dict = {}):
        # TODO: Support WebRTC and SIP agent codes.
        
        def attach_to_call(call_id: str):
            call_controller = controller_class(**controller_args)
            with GuavaSocket[Command, Event](
                    f"call-connection-{call_id}",
                    self.get_websocket_url(f"v2/connect-inbound/{call_id}"), 
                    headers=self._get_headers(),
                    serializer=lambda command: command.model_dump(),
                    deserializer=lambda e: decode_event_dict(e),
                    max_age_seconds=18000 # Conservatively kill the connection after 5 hours.
                ) as gs:
                
                def listen_for_events():
                    while gs.is_open():
                        event = gs.recv()
                        
                        # Process event on it's own thread, to allow for awaiting.
                        if event:
                            threading.Thread(target=call_controller.on_event, args=(event,), daemon=True).start()
                
                    
                listen_events_thread = threading.Thread(target=listen_for_events, daemon=True)
                listen_events_thread.start()
                
                # Drain commands directly in this thread.
                while gs.is_open():
                    command = call_controller._command_queue.get(block=True)
                    if isinstance(command, CommandQueueEnd):
                        break
                    
                    logger.debug("Sending command: %r for call ID: %s", command, call_id)
                    gs.send(command)

                listen_events_thread.join()
                
        query_string = urlencode({"phone_number": agent_number})
        with GuavaSocket[listen_inbound.ClientMessage, listen_inbound.ServerMessage](
                "listen-inbound",
                self.get_websocket_url(f"v2/listen-inbound?{query_string}"), # TODO: Allow WebRTC.
                headers=self._get_headers(),
                serializer=lambda msg: msg.model_dump(),
                deserializer=listen_inbound.decode_server_message,
            ) as gs:
            
            # Start listening and get the response.
            while gs.is_open():
                server_message = gs.recv()
                match server_message:
                    case listen_inbound.ListenStarted():
                        logger.info("Started listing on number %s. %d other listeners registered.", agent_number, server_message.other_listeners)
                    case listen_inbound.IncomingCall():
                        gs.send(listen_inbound.AcceptCall(call_id=server_message.call_id))
                    case listen_inbound.AssignCall():
                        threading.Thread(target=attach_to_call, args=(server_message.call_id, ), daemon=True).start()


    def send_sms(self, from_number: str, to_number: str, message: str) -> None:
        response = httpx.post(
            self.get_http_url("v1/send-sms"),
            json={
                "from_number": from_number,
                "to_number": to_number,
                "message": message,
            },
            headers=self._get_headers(),
        )
        response.raise_for_status()
